VALUES
  ('aboriginal-f0899a01-moex-00127', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公務人員辭職之權利，下列敘述何者正確？', '["公務人員提出辭職，除緊急情形外，應以書面為之", "針對公務人員所提辭職，服務機關或其上級機關應於收受辭職書之次日起30日內為准駁之決定", "公務人員之辭職，皆須經服務機關及其上級機關核准後，始生效力", "服務機關或其上級機關就公務人員辭職申請之准駁有裁量空間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00128', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者非屬公務員之懲戒處分種類？', '["免除職務", "停職", "記過", "罰款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00129', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '公務員如兼任非以營利為目的之事業職務，下列何者不符合公務員服務法之規定？', '["公務員兼任無給職工作不得影響其本職工作", "公務員兼任無給職工作不得影響政府信譽或與公務員有利益衝突", "公務員兼任無給職工作前應報經服務機關同意", "機關首長兼任無報酬且未影響本職工作應報經上級機關備查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00130', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公物利用關係之敘述，下列何者錯誤？', '["於道路兩旁舉辦婚喪喜慶活動，屬於公物之一般利用行為", "主管機關允許某電視台在某高山處所設立轉播站，屬於公物之特許利用", "主管機關將道路公告開放使用，其性質屬於行政處分", "某市政府同意業者利用下水道附掛有線電視纜線之行為，屬於公法上行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00131', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於法規命令之訂定，下列敘述何者錯誤？', '["法規命令之訂定得由人民或團體提議", "行政機關擬訂法規命令時，除情況急迫，顯然無法事先公告周知者外，應於政府公報或新聞紙公告 草案", "法規命令之發布，應刊登政府公報或新聞紙", "行政機關訂定法規命令，應舉行聽證會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00132', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者具有直接對外之效力？', '["解釋性行政規則", "法規命令", "處務規程", "裁量基準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00133', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '對年終考績列丁等公務員製發之免職令屬於何種行政行為？', '["事實行為", "行政處分", "行政契約", "行政指導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00134', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政處分附款之敘述，下列何者錯誤？', '["附款不得違背行政處分之目的", "行政機關作成行政處分有裁量權時，得為附款", "羈束處分於確保行政處分法定要件履行時，得為附款", "附解除條件之行政處分，於條件成就時，行政處分發生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00135', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '法規規定未滿2歲幼兒之父母或監護人得向衛生福利部申請育兒津貼，若當事人未申請，但衛生福利 部依然作成給予津貼之處分，則其效力為何？', '["自始無效", "得事後補正", "應依職權撤銷", "程序已完備處分合法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00136', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '行政機關對違反法律規定者裁處罰鍰，但於裁處書上漏未記載機關名稱，致無法得知作成機關時，該 處分之效力為何？', '["得撤銷", "得廢止", "效力未定", "無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
